async fn resolve_pilot(pilot: &Pilot) -> Option<PathBuf> {
    let path = resolve_cli(pilot.binary).await?;
    if pilot.probe_args.is_empty() {
        return Some(path);
    }
    Command::new(&path)
        .args(pilot.probe_args)
        .output()
        .await
        .ok()
        .filter(|o| o.status.success())
        .map(|_| path)
}

/// Resolve `<name>` to the executable this rover will invoke.
async fn resolve_cli(name: &str) -> Option<PathBuf> {
    if let Some(path) = cli_on_path(name) {
        return Some(path);
    }

    Command::new(name)
        .arg("--version")
        .output()
        .await
        .ok()
        .filter(|o| o.status.success())
        .map(|_| PathBuf::from(name))
}

fn cli_on_path(name: &str) -> Option<PathBuf> {
    cli_search_directories()
        .iter()
        .map(|directory| directory.join(name))
        .find(|path| is_executable_file(path))
}

fn cli_search_directories() -> Vec<PathBuf> {
    let mut directories = Vec::new();
    if let Some(path) = std::env::var_os("PATH") {
        directories.extend(std::env::split_paths(&path));
    }
    let mut out = Vec::with_capacity(directories.len());
    for directory in directories {
        if !out.contains(&directory) {
            out.push(directory);
        }
    }
    out
}

#[cfg(unix)]
fn is_executable_file(path: &Path) -> bool {
    fs::metadata(path)
        .map(|meta| meta.is_file() && meta.permissions().mode() & 0o111 != 0)
        .unwrap_or(false)
}

#[cfg(not(unix))]
fn is_executable_file(path: &Path) -> bool {
    fs::metadata(path)
        .map(|meta| meta.is_file())
        .unwrap_or(false)
}

/// Block a run because the pilot's CLI isn't installed on this rover.
async fn block_no_cli(
    client: &Client,
    hub: &str,
    token: &str,
    run_id: &str,
    name: &str,
) -> Result<()> {
    append_event(
        client,
        hub,
        token,
        run_id,
        "error",
        &format!("{name} CLI not available on this rover"),
    )
    .await?;
    set_state(client, hub, token, run_id, "blocked").await?;
    logline!("run {run_id} -> blocked (no {name})");
    Ok(())
}

#[allow(clippy::too_many_arguments)]
async fn log_pilot_start(
    client: &Client,
    hub: &str,
    token: &str,
    run_id: &str,
    name: &str,
    operation_directory: &Path,
    prompt: &str,
    resume: bool,
) -> Result<()> {
    let verb = if resume { "resume" } else { name };
    append_event(
        client,
        hub,
        token,
        run_id,
        "log",
        &format!(
            "{verb} in {}: {}",
            operation_directory.display(),
            first_line(prompt)
        ),
    )
    .await
}

/// Sentinel a pilot appends when it needs a human to answer before it can
/// continue. The Hub turns this into an "input requested" signal.
const NEEDS_INPUT_SENTINEL: &str = "@@UFO_NEEDS_INPUT@@";
const NEEDS_INPUT_INSTRUCTION: &str = "If you cannot proceed without a decision or information only a human can provide, do not guess: end your reply with a line containing exactly @@UFO_NEEDS_INPUT@@ followed by your question.";
// The pilot may set the operation's status by emitting @@UFO_STATUS:<status>@@.
const STATUS_PREFIX: &str = "@@UFO_STATUS:";
const STATUS_INSTRUCTION: &str = "By default, finishing leaves the operation In Review for a human. To set a different outcome, end your reply with a line containing exactly @@UFO_STATUS:<status>@@ where <status> is one of in_review, done, blocked, cancelled.";

// Captain split protocol.
const SUB_OPERATIONS_SENTINEL: &str = "@@UFO_SUB_OPERATIONS@@";
const SUB_OPERATIONS_INSTRUCTION: &str = "If this operation splits cleanly into independent, non-overlapping pieces that can run in parallel, do the planning/research first, then end your reply with a line containing exactly @@UFO_SUB_OPERATIONS@@ followed by a JSON array of objects {\"title\": string, \"body\": string, \"assignee\": optional pilot kind}. Each piece must touch different files/areas so they merge cleanly. Omit this entirely if the work is not worth splitting.";

/// Parse the JSON array after @@UFO_SUB_OPERATIONS@@.
fn parse_sub_operations(msg: &str) -> Option<serde_json::Value> {
    let i = msg.find(SUB_OPERATIONS_SENTINEL)?;
    let rest = msg[i + SUB_OPERATIONS_SENTINEL.len()..].trim();
    let v: serde_json::Value = serde_json::from_str(rest).ok()?;
    v.is_array().then_some(v)
}

/// Remove the @@UFO_SUB_OPERATIONS@@ marker and its trailing JSON from the human message.
fn strip_sub_operations(msg: &str) -> String {
    match msg.find(SUB_OPERATIONS_SENTINEL) {
        Some(i) => msg[..i].trim().to_string(),
        None => msg.to_string(),
    }
}

/// Extract a pilot-requested status from @@UFO_STATUS:x@@, if present.
fn parse_status(msg: &str) -> Option<String> {
    let i = msg.find(STATUS_PREFIX)?;
    let rest = &msg[i + STATUS_PREFIX.len()..];
    let end = rest
        .find("@@")
        .or_else(|| rest.find('\n'))
        .unwrap_or(rest.len());
    let status = rest[..end].trim().trim_end_matches('\r');
    matches!(status, "in_review" | "done" | "blocked" | "cancelled").then(|| status.to_string())
}

/// Remove a @@UFO_STATUS:x@@ marker from the message the human sees.
fn strip_status(msg: &str) -> String {
    let Some(i) = msg.find(STATUS_PREFIX) else {
        return msg.to_string();
    };
    let rest = &msg[i + STATUS_PREFIX.len()..];
    let end = rest
        .find("@@")
        .or_else(|| rest.find('\n'))
        .unwrap_or(rest.len());
    let status = rest[..end].trim().trim_end_matches('\r');
    if !matches!(status, "in_review" | "done" | "blocked" | "cancelled") {
        return msg.to_string();
    }
    let marker_end =
        i + STATUS_PREFIX.len() + end + rest[end..].strip_prefix("@@").map_or(0, |_| 2);
    format!("{}{}", &msg[..i], &msg[marker_end..])
        .trim()
        .to_string()
}

/// Run a claimed operation with its assigned pilot, then capture a diff.
async fn execute_run(
    client: &Client,
    hub: &str,
    token: &str,
    run: &ClaimedRun,
    operation_directory: &Path,
    caps: PilotCaps,
) -> Result<()> {
    let pilot = run.pilot.as_str();

    // The operation title + body, with the needs-input + status protocols appended.
    let prompt = if run.prompt.trim().is_empty() {
        "Describe this repository in a new file SUMMARY.md.".to_string()
    } else {
        run.prompt.clone()
    };
    let mut cli_prompt = format!("{prompt}\n\n{NEEDS_INPUT_INSTRUCTION}\n{STATUS_INSTRUCTION}");
    if run.can_propose_sub_operations {
        cli_prompt.push('\n');
        cli_prompt.push_str(SUB_OPERATIONS_INSTRUCTION);
    }

    let resume = !run.session_id.is_empty();

    let Some(pilot) = find_pilot(pilot) else {
        append_event(
            client,
            hub,
            token,
            &run.id,
            "error",
            &format!(
                "unsupported pilot '{pilot}' (supported: {})",
                supported_pilots()
            ),
        )
        .await?;
        set_state(client, hub, token, &run.id, "blocked").await?;
        return Ok(());
    };
    let Some(executable) = caps.path(pilot.kind) else {
        return block_no_cli(client, hub, token, &run.id, pilot.binary).await;
    };
    log_pilot_start(
        client,
        hub,
        token,
        &run.id,
        pilot.kind,
        operation_directory,
        &prompt,
        resume,
    )
    .await?;
    let mut cmd = (pilot.command)(executable, run, &cli_prompt, operation_directory);

    set_state(client, hub, token, &run.id, "running").await?;

    let pilot_run = async {
        match pilot.output {
            PilotOutput::JsonLines => {
                run_streaming_json(client, hub, token, &run.id, &mut cmd).await
            }
            PilotOutput::PlainText => {
                let (status, message) =
                    run_streaming(client, hub, token, &run.id, &mut cmd).await?;
                let session = if pilot.kind == "openclaw" {
                    openclaw_session_key(run)
                } else {
                    String::new()
                };
                Ok((status, session, message))
            }
        }
    };
    tokio::pin!(pilot_run);
    let lease = heartbeat(client, hub, token, &run.id);
    tokio::pin!(lease);

    let (status, session, mut message) = tokio::select! {
        result = &mut pilot_run => result?,
        result = &mut lease => {
            result?;
            return Err(anyhow!("heartbeat stopped unexpectedly"));
        }
    };

    // Sentinels are protocol markers, not part of the human-visible comment.
    let needs_input = message.contains(NEEDS_INPUT_SENTINEL);
    if needs_input {
        message = message.replace(NEEDS_INPUT_SENTINEL, "").trim().to_string();
    }
    let operation_status = parse_status(&message).unwrap_or_default();
    if !operation_status.is_empty() {
        message = strip_status(&message);
    }
    let sub_operations = parse_sub_operations(&message);
    if sub_operations.is_some() {
        message = strip_sub_operations(&message);
    }

    // Capture the working-tree diff (include untracked via intent-to-add).
    let _ = git(operation_directory, &["add", "-N", "."]).await;
    let diff = git(operation_directory, &["diff"])
        .await
        .unwrap_or_default();
    let content = if diff.trim().is_empty() {
        "(no changes)".to_string()
    } else {
        diff
    };
    upload_artifact(client, hub, token, &run.id, "diff", "git.diff", &content).await?;

    // Record the session + post the pilot's final message as a comment.
    post_result(
        client,
        hub,
        token,
        &run.id,
        &session,
        &message,
        needs_input,
        &operation_status,
        sub_operations.as_ref(),
    )
    .await?;

    let final_state = if status.success() {
        "succeeded"
    } else {
        "failed"
    };
    append_event(
        client,
        hub,
        token,
        &run.id,
        "result",
        &format!("pilot exited with {:?}", status.code()),
    )
    .await?;
    set_state(client, hub, token, &run.id, final_state).await?;
    logline!("run {} -> {}", &run.id, final_state);
    Ok(())
}

fn first_line(s: &str) -> &str {
    s.lines().next().unwrap_or("")
}

/// Renew the run's lease every 5s, returning if the hub says ownership was lost.
async fn heartbeat(client: &Client, hub: &str, token: &str, run_id: &str) -> Result<()> {
    loop {
        sleep(Duration::from_secs(5)).await;
        match client
            .put(hub_url(hub, format!("rover/runs/{run_id}/heartbeat")))
            .bearer_auth(token)
            .send()
            .await
        {
            Ok(resp) if resp.status().is_success() => {}
            Ok(resp)
                if matches!(
                    resp.status(),
                    StatusCode::NOT_FOUND | StatusCode::UNAUTHORIZED
                ) =>
            {
                return Err(RunLeaseLost.into());
            }
            Ok(resp) => logline!("heartbeat run {run_id} -> {}", resp.status()),
            Err(e) => logline!("heartbeat run {run_id} failed: {e}"),
        }
    }
}

/// Spawn the command (stdout+stderr piped), stream both as log events, and wait.
async fn run_streaming(
    client: &Client,
    hub: &str,
    token: &str,
    run_id: &str,
    cmd: &mut Command,
) -> Result<(std::process::ExitStatus, String)> {
    cmd.stdout(Stdio::piped()).stderr(Stdio::piped());
    cmd.kill_on_drop(true);
    let mut child = cmd.spawn()?;
    let stdout = child.stdout.take().ok_or_else(|| anyhow!("no stdout"))?;
    let stderr = child.stderr.take().ok_or_else(|| anyhow!("no stderr"))?;

    // Drain stderr concurrently so a full pipe can't deadlock the child.
    let err_task = {
        let client = client.clone();
        let hub = hub.to_string();
        let token = token.to_string();
        let run_id = run_id.to_string();
        tokio::spawn(async move {
            let mut lines = BufReader::new(stderr).lines();
            while let Ok(Some(line)) = lines.next_line().await {
                let _ = client
                    .post(hub_url(&hub, format!("rover/runs/{run_id}/events")))
                    .bearer_auth(&token)
                    .json(&json!({ "kind": "log", "message": line }))
                    .send()
                    .await;
            }
        })
    };

    // Shell output is the transcript: stream each stdout line as a text message.
    let mut sequence: i64 = 0;
    let mut message = String::new();
    let mut lines = BufReader::new(stdout).lines();
    while let Some(line) = lines.next_line().await? {
        logline!("[run {run_id}] {line}");
        if !message.is_empty() {
            message.push('\n');
        }
        message.push_str(&line);
        post_message(
            client,
            hub,
            token,
            run_id,
            &mut sequence,
            "text",
            None,
            Some(&line),
            None,
            None,
        )
        .await?;
    }

    let status = child.wait().await?;
    let _ = err_task.await;
    Ok((status, message))
}

/// Like run_streaming but parses structured JSONL pilot output:
/// streams readable lines as log events and returns (status, session_id, message).
async fn run_streaming_json(
    client: &Client,
    hub: &str,
    token: &str,
    run_id: &str,
    cmd: &mut Command,
) -> Result<(std::process::ExitStatus, String, String)> {
    cmd.stdout(Stdio::piped()).stderr(Stdio::piped());
    cmd.kill_on_drop(true);
    let mut child = cmd.spawn()?;
    let stdout = child.stdout.take().ok_or_else(|| anyhow!("no stdout"))?;
    let stderr = child.stderr.take().ok_or_else(|| anyhow!("no stderr"))?;

    let err_task = {
        let client = client.clone();
        let hub = hub.to_string();
        let token = token.to_string();
        let run_id = run_id.to_string();
        tokio::spawn(async move {
            let mut lines = BufReader::new(stderr).lines();
            while let Ok(Some(line)) = lines.next_line().await {
                let _ = client
                    .post(hub_url(&hub, format!("rover/runs/{run_id}/events")))
                    .bearer_auth(&token)
                    .json(&json!({ "kind": "log", "message": line }))
                    .send()
                    .await;
            }
        })
    };

    let mut session = String::new();
    let mut message = String::new();
    let mut sequence: i64 = 0;
    let mut lines = BufReader::new(stdout).lines();
    while let Some(line) = lines.next_line().await? {
        let trimmed = line.trim();
        if trimmed.is_empty() {
            continue;
        }
        let v: serde_json::Value = match serde_json::from_str(trimmed) {
            Ok(v) => v,
            Err(_) => {
                post_message(
                    client,
                    hub,
                    token,
                    run_id,
                    &mut sequence,
                    "text",
                    None,
                    Some(trimmed),
                    None,
                    None,
                )
                .await?;
                continue;
            }
        };
        if let Some(s) = v.get("session_id").and_then(|x| x.as_str())
            && !s.is_empty()
        {
            session = s.to_string();
        }
        if v.get("type").and_then(|x| x.as_str()) == Some("thread.started")
            && let Some(s) = v.get("thread_id").and_then(|x| x.as_str())
        {
            session = s.to_string();
        }
        process_event(client, hub, token, run_id, &mut sequence, &v, &mut message).await?;
    }

    let status = child.wait().await?;
    let _ = err_task.await;
    Ok((status, session, message))
}

/// Translate one structured JSON pilot event into transcript messages.
async fn process_event(
    client: &Client,
    hub: &str,
    token: &str,
    run_id: &str,
    sequence: &mut i64,
    v: &serde_json::Value,
    message: &mut String,
) -> Result<()> {
    match v.get("type").and_then(|x| x.as_str()) {
        // claude: an assistant turn carries text / thinking / tool_use blocks.
        Some("assistant") => {
            if let Some(content) = v
                .get("message")
                .and_then(|m| m.get("content"))
                .and_then(|c| c.as_array())
            {
                for item in content {
                    match item.get("type").and_then(|x| x.as_str()) {
                        Some("text") => {
                            if let Some(t) = item.get("text").and_then(|x| x.as_str())
                                && !t.trim().is_empty()
                            {
                                post_message(
                                    client,
                                    hub,
                                    token,
                                    run_id,
                                    sequence,
                                    "text",
                                    None,
                                    Some(t),
                                    None,
                                    None,
                                )
                                .await?;
                            }
                        }
                        Some("thinking") => {
                            if let Some(t) = item.get("thinking").and_then(|x| x.as_str()) {
                                post_message(
                                    client,
                                    hub,
                                    token,
                                    run_id,
                                    sequence,
                                    "thinking",
                                    None,
                                    Some(t),
                                    None,
                                    None,
                                )
                                .await?;
                            }
                        }
                        Some("tool_use") => {
                            let name = item.get("name").and_then(|x| x.as_str()).unwrap_or("tool");
                            post_message(
                                client,
                                hub,
                                token,
                                run_id,
                                sequence,
                                "tool_use",
                                Some(name),
                                None,
                                item.get("input").cloned(),
                                None,
                            )
                            .await?;
                        }
                        _ => {}
                    }
                }
            }
        }
        // claude: tool results come back as a user message.
        Some("user") => {
            if let Some(content) = v
                .get("message")
                .and_then(|m| m.get("content"))
                .and_then(|c| c.as_array())
            {
                for item in content {
                    if item.get("type").and_then(|x| x.as_str()) == Some("tool_result") {
                        let out = tool_result_text(item.get("content"));
                        post_message(
                            client,
                            hub,
                            token,
                            run_id,
                            sequence,
                            "tool_result",
                            None,
                            None,
                            None,
                            Some(&out),
                        )
                        .await?;
                    }
                }
            }
        }
        Some("result") => {
            if let Some(t) = v.get("result").and_then(|x| x.as_str()) {
                *message = t.to_string();
            }
        }
        // codex: each item.completed is a step.
        Some("item.completed") => {
            if let Some(item) = v.get("item") {
                match item.get("type").and_then(|x| x.as_str()) {
                    // External Codex JSON uses this literal for assistant output.
                    Some("agent_message") => {
                        if let Some(t) = item.get("text").and_then(|x| x.as_str()) {
                            *message = t.to_string();
                            post_message(
                                client,
                                hub,
                                token,
                                run_id,
                                sequence,
                                "text",
                                None,
                                Some(t),
                                None,
                                None,
                            )
                            .await?;
                        }
                    }
                    Some("reasoning") => {
                        if let Some(t) = item.get("text").and_then(|x| x.as_str()) {
                            post_message(
                                client,
                                hub,
                                token,
                                run_id,
                                sequence,
                                "thinking",
                                None,
                                Some(t),
                                None,
                                None,
                            )
                            .await?;
                        }
                    }
                    Some("command_execution") => {
                        let cmd = item.get("command").and_then(|x| x.as_str()).unwrap_or("");
                        post_message(
                            client,
                            hub,
                            token,
                            run_id,
                            sequence,
                            "tool_use",
                            Some("shell"),
                            None,
                            Some(json!({ "command": cmd })),
                            None,
                        )
                        .await?;
                        if let Some(out) = item
                            .get("aggregated_output")
                            .or_else(|| item.get("output"))
                            .and_then(|x| x.as_str())
                            && !out.trim().is_empty()
                        {
                            post_message(
                                client,
                                hub,
                                token,
                                run_id,
                                sequence,
                                "tool_result",
                                Some("shell"),
                                None,
                                None,
                                Some(out),
                            )
                            .await?;
                        }
                    }
                    Some("file_change") => {
                        post_message(
                            client,
                            hub,
                            token,
                            run_id,
                            sequence,
                            "tool_use",
                            Some("edit"),
                            None,
                            item.get("changes").cloned(),
                            None,
                        )
                        .await?;
                    }
                    _ => {}
                }
            }
        }
        _ => {}
    }
    Ok(())
}

/// Claude tool_result content is either a string or an array of text blocks.
fn tool_result_text(content: Option<&serde_json::Value>) -> String {
    match content {
        Some(serde_json::Value::String(s)) => s.clone(),
        Some(serde_json::Value::Array(arr)) => arr
            .iter()
            .filter_map(|b| b.get("text").and_then(|x| x.as_str()))
            .collect::<Vec<_>>()
            .join("\n"),
        _ => String::new(),
    }
}

/// Post one typed transcript message and advance the per-run sequence.
#[allow(clippy::too_many_arguments)]
async fn post_message(
    client: &Client,
    hub: &str,
    token: &str,
    run_id: &str,
    sequence: &mut i64,
    mtype: &str,
    tool: Option<&str>,
    content: Option<&str>,
    input: Option<serde_json::Value>,
    output: Option<&str>,
) -> Result<()> {
    let mut body = serde_json::Map::new();
    body.insert("sequence".into(), json!(*sequence));
    body.insert("type".into(), json!(mtype));
    if let Some(t) = tool {
        body.insert("tool".into(), json!(t));
    }
    if let Some(c) = content {
        body.insert("content".into(), json!(c));
    }
    if let Some(i) = input {
        body.insert("input".into(), i);
    }
    if let Some(o) = output {
        body.insert("output".into(), json!(o));
    }
    *sequence += 1;
    let resp = client
        .post(hub_url(hub, format!("rover/runs/{run_id}/messages")))
        .bearer_auth(token)
        .json(&serde_json::Value::Object(body))
        .send()
        .await?;
    if matches!(
        resp.status(),
        StatusCode::NOT_FOUND | StatusCode::UNAUTHORIZED
    ) {
        return Err(RunLeaseLost.into());
    }
    if !resp.status().is_success() {
        logline!("message post run {run_id} -> {}", resp.status());
    }
    Ok(())
}

#[allow(clippy::too_many_arguments)]
async fn post_result(
    client: &Client,
    hub: &str,
    token: &str,
    run_id: &str,
    session: &str,
    message: &str,
    needs_input: bool,
    operation_status: &str,
    sub_operations: Option<&serde_json::Value>,
) -> Result<()> {
    let mut body = json!({ "session_id": session, "message": message, "needs_input": needs_input, "operation_status": operation_status });
    if let Some(s) = sub_operations {
        body["sub_operations"] = s.clone();
    }
    let resp = client
        .post(hub_url(hub, format!("rover/runs/{run_id}/result")))
        .bearer_auth(token)
        .json(&body)
        .send()
        .await?;
    if matches!(
        resp.status(),
        StatusCode::NOT_FOUND | StatusCode::UNAUTHORIZED
    ) {
        return Err(RunLeaseLost.into());
    }
    if !resp.status().is_success() {
        return Err(anyhow!("result post returned {}", resp.status()));
    }
    Ok(())
}

